export async function POST(req: Request) {
  try {
    const { images, prompt, mode } = await req.json();

    if (mode === "manual") {
      return NextResponse.json({ comercio: "MANUAL", productos: [], total: 0 });
    }

    if (!images || images.length === 0) {
      // Este check ya está en el cliente, pero es bueno tenerlo aquí también.
      return NextResponse.json({ error: "No se recibieron imágenes para analizar." }, { status: 400 });
    }

    let allRawTranscriptions: string[] = [];

    console.log(`[V2.0 Pipeline] Paso A: Iniciando Visión SOLO con Mistral...`);

    if (images.length === 1) {
      let transcriptionAttempted = false;
      let mistralApiKeyIndex = 0;

      while (!transcriptionAttempted) {
        const mistralApiKey = getMistralApiKey(mistralApiKeyIndex);
        if (mistralApiKey) {
          try {
            console.log(`Intentando transcripción con Mistral (1 foto) - Clave ${mistralApiKeyIndex + 1}...`);
            const rawTranscription = await callMistralVision(mistralApiKey, images, "Transcribe literalmente este ticket de compra. Mantén los precios al lado de sus productos.");
            allRawTranscriptions.push(rawTranscription);
            transcriptionAttempted = true;
          } catch (error: any) {
            console.error(`Fallo en Mistral para 1 foto (Clave ${mistralApiKeyIndex + 1}):`, error.message);
            mistralApiKeyIndex++;
            if (!getMistralApiKey(mistralApiKeyIndex)) {
              // Si no quedan más claves de Mistral, lanzamos el error final.
              throw new Error("Todas las claves de Mistral han fallado para procesar la imagen.");
            }
          }
        } else {
          // Si no hay claves de Mistral disponibles desde el principio.
          throw new Error("No hay claves de Mistral configuradas.");
        }
      }
    } else if (images.length > 1 && images.length <= 3) {
      // Procesamos imágenes en paralelo, cada una intentando con Mistral.
      const visionPromises = images.map(async (img: string, index: number) => {
        let transcriptionAttempted = false;
        let mistralApiKeyIndex = 0;

        while (!transcriptionAttempted) {
          const mistralApiKey = getMistralApiKey(mistralApiKeyIndex);
          if (mistralApiKey) {
            try {
              console.log(`Intentando transcripción de imagen ${index + 1} con Mistral - Clave ${mistralApiKeyIndex + 1}...`);
              const rawTranscription = await callMistralVision(mistralApiKey, [img], `Transcribe literalmente la imagen ${index + 1} de este ticket de compra. Mantén los precios al lado de sus productos.`);
              transcriptionAttempted = true;
              return rawTranscription;
            } catch (error: any) {
              console.error(`Fallo en Mistral para imagen ${index + 1} (Clave ${mistralApiKeyIndex + 1}):`, error.message);
              mistralApiKeyIndex++;
              if (!getMistralApiKey(mistralApiKeyIndex)) {
                // Si no quedan más claves de Mistral para esta imagen específica.
                throw new Error(`Todas las claves de Mistral han fallado para la imagen ${index + 1}.`);
              }
            }
          } else {
            // Si no hay claves de Mistral disponibles para esta imagen.
            throw new Error(`No hay claves de Mistral disponibles para la imagen ${index + 1}.`);
          }
        }
        // Si el bucle termina sin éxito (lo cual no debería ocurrir si los throws funcionan)
        throw new Error(`Fallo desconocido en la transcripción para la imagen ${index + 1} con Mistral.`);
      });

      allRawTranscriptions = await Promise.all(visionPromises);
    } else {
      // Ya cubierto en el check inicial, pero por si acaso.
      return NextResponse.json({ error: "Número de imágenes no soportado. Máximo 3." }, { status: 400 });
    }

    // Verificación final de transcripción combinada
    const combinedTranscription = Array.from(new Set(allRawTranscriptions.join("\n").split("\n"))).join("\n");
    if (!combinedTranscription.trim()) {
      // Si después de todos los intentos Mistral no pudo extraer texto.
      throw new Error("Mistral no pudo extraer texto válido de las imágenes.");
    }

    // --- PASO B: RAZONAMIENTO (Groq / Llama 3.3 70B como sintetizador) ---
    // MANTENEMOS GROQ PARA EL RAZONAMIENTO SEGÚN ARQUITECTURA ORIGINAL
    console.log("[V2.0 Pipeline] Paso B: Iniciando Razonamiento y Validación con Groq...");
    let groqApiKeyIndex = 0;
    let reasoningAttempted = false;
    let finalResult: string | undefined;

    while (!reasoningAttempted) {
      let groqApiKey = getGroqApiKey(groqApiKeyIndex);
      if (groqApiKey) {
        try {
          const groqResponse = await fetch("https://api.groq.com/openai/v1/chat/completions", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "Authorization": `Bearer ${groqApiKey}`
            },
            body: JSON.stringify({
              model: "llama-3.3-70b-versatile", // Modelo de razonamiento
              messages: [
                {
                  role: "system",
                  content: "Sintetiza texto de tickets en JSON. Asegura coherencia de totales y ajusta productos si hay discrepancias. Formato: {comercio, fecha, total, productos: [{cantidad, nombre_ticket, subtotal}]}. Solo responde con el JSON."
                },
                {
                  role: "user",
                  content: `${prompt} \n\n TEXTO TRANSCRITO (Mistral): \n ${combinedTranscription}`
                }
              ],
              temperature: 0.1,
              response_format: { type: "json_object" }
            })
          });

          if (!groqResponse.ok) {
            const errorData = await groqResponse.json();
            console.error("Error en Groq API:", errorData);
            if (groqResponse.status === 429 || groqResponse.status >= 500) {
              throw new Error(`Groq API error (status: ${groqResponse.status}), intentando con otra clave.`);
            } else {
              throw new Error(errorData.error?.message || "Error desconocido al razonar con Groq.");
            }
          }

          const groqData = await groqResponse.json();
          if (!groqData.choices?.[0]?.message?.content) {
            throw new Error("Groq no pudo generar un contenido válido.");
          }
          finalResult = groqData.choices[0].message.content;
          reasoningAttempted = true;
          break;
        } catch (error: any) {
          console.error("Fallo en Groq, intentando con otra clave:", error.message);
          groqApiKeyIndex++;
          if (!getGroqApiKey(groqApiKeyIndex)) {
            throw new Error("Todas las claves de Groq han fallado para el razonamiento.");
          }
        }
      } else {
        throw new Error("No hay claves de Groq disponibles para el razonamiento.");
      }
    }

    if (!finalResult) {
      throw new Error("El modelo de razonamiento no pudo generar un resultado final.");
    }
    return NextResponse.json(JSON.parse(finalResult));

  } catch (error: any) {
    console.error("--- FALLO CRÍTICO PIPELINE (Mistral Vision / Groq Reasoning) ---", error);
    // Capturamos errores tanto de visión (Mistral) como de razonamiento (Groq).
    return NextResponse.json({ error: error.message || "Error interno en el pipeline" }, { status: 500 });
  }
}

/* --- ARCHIVO: app/api/auth/refresh/route.ts --- */
import { NextResponse } from 'next/server';
import { CLIENT_ID } from '@/lib/config';

export async function POST(request: Request) {
    try {
        const { refresh_token } = await request.json();
        const client_secret = process.env.GOOGLE_CLIENT_SECRET;

        if (!client_secret) return NextResponse.json({ error: 'Secret missing' }, { status: 500 });

        const response = await fetch('https://oauth2.googleapis.com/token', {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: new URLSearchParams({
                refresh_token,
                client_id: CLIENT_ID, // Usamos la variable unificada
                client_secret,
                grant_type: 'refresh_token',
            }),
        });

        const data = await response.json();
        return NextResponse.json(data);
    } catch (error) {
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

/* --- ARCHIVO: app/api/auth/token/route.ts --- */
import { NextResponse } from 'next/server';
import { CLIENT_ID } from '@/lib/config'; // Importamos el ID único

export async function POST(request: Request) {
    try {
        const { code } = await request.json();
        const client_secret = process.env.GOOGLE_CLIENT_SECRET;

        if (!client_secret) {
            console.error("❌ GOOGLE_CLIENT_SECRET no configurado en Vercel");
            return NextResponse.json({ error: 'Server secret missing' }, { status: 500 });
        }

        const response = await fetch('https://oauth2.googleapis.com/token', {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: new URLSearchParams({
                code,
                client_id: CLIENT_ID, // Usamos la variable unificada
                client_secret,
                grant_type: 'authorization_code',
                redirect_uri: 'postmessage',
            }),
        });

        const data = await response.json();

        if (!response.ok) {
            console.error("❌ Error de Google Auth:", data);
            return NextResponse.json(data, { status: response.status });
        }

        return NextResponse.json(data);
    } catch (error) {
        return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
    }
}

"use client";
import React, { useState } from 'react';
import { ShoppingCart, Loader2 } from 'lucide-react';

interface AuthViewProps {
  CLIENT_ID: string;
  txt: (key: string) => string;
}

const AuthView: React.FC<AuthViewProps> = ({ CLIENT_ID, txt }) => {
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  const handleLogin = () => {
    setIsLoggingIn(true);

    // @ts-ignore
    if (!window.google) {
      alert("El SDK de Google no se ha cargado todavía. Por favor, refresca la página.");
      setIsLoggingIn(false);
      return;
    }

    console.log("🚀 Iniciando flujo de autenticación...");

    // SEGURIDAD: Si en 40 segundos no hay respuesta, liberamos el botón
    const safetyTimer = setTimeout(() => {
      setIsLoggingIn(false);
      console.warn("⚠️ Tiempo de espera agotado o ventana cerrada por el usuario.");
    }, 40000);

    // @ts-ignore
    const client = window.google.accounts.oauth2.initCodeClient({
      client_id: CLIENT_ID,
      scope: "https://www.googleapis.com/auth/drive.appdata https://www.googleapis.com/auth/userinfo.profile",
      ux_mode: 'popup',
      select_account: true, // Obliga a mostrar el selector de cuentas (más compatible)
      callback: async (response: any) => {
        // Limpiamos el timer de seguridad al recibir respuesta
        clearTimeout(safetyTimer);

        if (response.code) {
          console.log("✅ Código de autorización recibido. Intercambiando...");
          try {
            // 1. Intercambio de código por tokens en el servidor
            const tokenRes = await fetch('/api/auth/token', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({ code: response.code })
            });

            if (!tokenRes.ok) throw new Error("Fallo en la respuesta del servidor (/api/auth/token)");

            const res = await tokenRes.json();

            if (res.access_token) {
              console.log("✅ Tokens obtenidos. Guardando sesión...");
              localStorage.setItem('gdrive_token', res.access_token);
              if (res.refresh_token) {
                localStorage.setItem('gdrive_refresh_token', res.refresh_token);
              }

              // 2. Obtener información del perfil
              const userRes = await fetch("https://www.googleapis.com/oauth2/v3/userinfo", { 
                headers: { Authorization: `Bearer ${res.access_token}` } 
              });

              if (userRes.ok) {
                const info = await userRes.json();
                localStorage.setItem('user_name', info.name);
              } else {
                localStorage.setItem('user_name', "Usuario");
              }

              console.log("🎉 Login exitoso. Recargando...");
              window.location.reload();
            } else {
              throw new Error("No se recibió access_token del servidor");
            }
          } catch (error) {
            console.error("❌ Error en el proceso de tokens:", error);
            alert("Error al validar la sesión con el servidor.");
            setIsLoggingIn(false);
          }
        } else {
          console.error("❌ Google no devolvió un código");
          setIsLoggingIn(false);
        }
      },
      error_callback: (err: any) => {
        clearTimeout(safetyTimer);
        console.error("❌ Error de Google Sign-In:", err);
        setIsLoggingIn(false);
      }
    });

    try {
      client.requestCode();
    } catch (err) {
      console.error("❌ Error al abrir el popup de Google:", err);
      clearTimeout(safetyTimer);
      setIsLoggingIn(false);
    }
  };

  return (
    <main className="app-layout justify-center items-center text-center relative overflow-hidden pt-4 lg:pt-0">
      <div className="absolute top-[-10%] left-[-20%] w-[80%] h-[40%] bg-brand-primary/10 rounded-full blur-[120px] animate-pulse" />

      <div className="relative z-10 w-full flex flex-col items-center">
        <div className="relative mb-12">
          <div className="w-24 h-24 bg-brand-primary rounded-[2.5rem] mx-auto flex items-center justify-center shadow-[0_25px_60px_-15px_rgba(93,46,239,0.5)] rotate-12">
            <ShoppingCart className="text-white" size={48} strokeWidth={2.5} />
          </div>
        </div>

        <div className="space-y-6 mb-16 px-4">
          <h1 className="heading-1 text-5xl tracking-tighter leading-[0.8]">
            {txt('auth.title')} <span className="text-brand-primary block">{txt('auth.app')}</span>
          </h1>
          <p className="text-[10px] font-black uppercase tracking-[0.4em] text-brand-muted">
            {txt('auth.subtitle')}
          </p>
        </div>

        <div className="w-full max-w-xs space-y-4">
          <button 
            onClick={handleLogin} 
            disabled={isLoggingIn}
            className="w-full group relative flex items-center bg-white text-black font-bold py-4 px-6 rounded-2xl transition-all duration-300 active:scale-95 shadow-xl disabled:opacity-50 min-h-[56px] justify-center"
          >
            {isLoggingIn ? (
              <Loader2 className="animate-spin text-black" size={24} />
            ) : (
              <div className="flex items-center w-full">
                <div className="bg-white p-0.5 rounded-lg mr-4">
                  <svg width="20" height="20" viewBox="0 0 24 24">
                    <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                    <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                    <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z" fill="#FBBC05"/>
                    <path d="M12 5.38c1.62 0 3.06.56 4.21 1.66l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 12-4.53z" fill="#EA4335"/>
                  </svg>
                </div>
                <span className="flex-1 text-center text-sm">{txt('auth.login_btn')}</span>
              </div>
            )}
          </button>

          <p className="text-[8px] font-bold text-brand-muted uppercase tracking-widest leading-relaxed px-4">
            {txt('auth.footer')}
          </p>
        </div>
      </div>
    </main>
  );
};

export default AuthView;

"use client";
import React from 'react';
import { AlertCircle, CheckCircle2, X } from 'lucide-react';

interface ConfirmModalProps {
  isOpen: boolean;
  title: string;
  message: string;
  onConfirm: () => void;
  onCancel: () => void;
  confirmText?: string;
  cancelText?: string;
  type?: 'danger' | 'info';
}

const ConfirmModal: React.FC<ConfirmModalProps> = ({
  isOpen,
  title,
  message,
  onConfirm,
  onCancel,
  confirmText = "ACEPTAR",
  cancelText = "CANCELAR",
  type = 'info'
}) => {
  if (!isOpen) return null;

  return (
    <div className="modal-overlay">
      <div className="card-premium w-[92%] max-w-md !p-6 lg:!p-8 relative overflow-hidden animate-in zoom-in-95 duration-200">
        {/* Glow effect */}
        <div className={`absolute -top-24 -left-24 w-48 h-48 blur-[80px] rounded-full opacity-20 ${
          type === 'danger' ? 'bg-brand-danger' : 'bg-brand-primary'
        }`} />

        <div className="relative z-10 space-y-5 lg:space-y-6">
          <div className="flex items-center gap-4">
            <div className={`p-3 lg:p-4 rounded-2xl shrink-0 ${
              type === 'danger' ? 'bg-brand-danger/10 text-brand-danger' : 'bg-brand-primary/10 text-brand-primary'
            }`}>
              {type === 'danger' ? <AlertCircle size={24} className="lg:w-7 lg:h-7" /> : <CheckCircle2 size={24} className="lg:w-7 lg:h-7" />}
            </div>
            <div className="min-w-0">
              <h3 className="text-base lg:text-lg font-black uppercase italic tracking-tighter leading-none mb-1 truncate">{title}</h3>
              <p className="text-[9px] font-black uppercase tracking-widest text-brand-muted/40 italic truncate">
                {type === 'danger' ? 'Acción Crítica' : 'Confirmación'}
              </p>
            </div>
          </div>

          <p className="text-[11px] lg:text-sm font-bold text-white/70 leading-relaxed uppercase tracking-tight line-clamp-3">
            {message}
          </p>

          <div className="flex gap-2.5 lg:gap-3 pt-2 items-stretch">
            <button 
              onClick={onCancel}
              className="btn-secondary !py-3 lg:!py-4 flex-1 bg-white/5 border-white/10 text-brand-muted hover:text-white !text-[9px] lg:!text-[11px] !px-2 leading-none"
            >
              <span className="truncate w-full block text-center">{cancelText}</span>
            </button>
            <button 
              onClick={onConfirm}
              className={`btn-primary !py-3 lg:!py-4 flex-[1.4] !text-[9px] lg:!text-[11px] !px-2 leading-none ${
                type === 'danger' ? 'bg-brand-danger shadow-brand-danger/20' : ''
              }`}
            >
              <span className="truncate w-full block text-center">{confirmText}</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ConfirmModal;

"use client";
import React, { useState, useMemo } from 'react';
import { 
  ChevronLeft, 
  ChevronRight, 
  Store, 
  TrendingUp, 
  ShoppingCart, 
  Utensils, 
  Pill, 
  LayoutGrid,
  ArrowUpRight,
  Tag,
  PieChart as PieIcon
} from 'lucide-react';

interface DashboardViewProps {
  stats: {
    total: number;
    currentGastos: any[];
    porComercio: Record<string, number>;
  };
  currentViewDate: Date;
  setCurrentViewDate: (date: Date) => void;
  setSelectedGasto: (gasto: any) => void;
  setActiveTab: (tab: string) => void;
  txt: (key: string) => string;
  lang: string;
}

const DashboardView: React.FC<DashboardViewProps> = ({ 
  stats, 
  currentViewDate, 
  setCurrentViewDate, 
  setSelectedGasto, 
  setActiveTab, 
  txt, 
  lang 
}) => {
  const [showBreakdown, setShowBreakdown] = useState(false);

  const changeMonth = (offset: number) => {
    setCurrentViewDate(new Date(currentViewDate.getFullYear(), currentViewDate.getMonth() + offset, 1));
  };

  const isCurrentMonth = currentViewDate.getMonth() === new Date().getMonth() && 
                         currentViewDate.getFullYear() === new Date().getFullYear();

  const statsPorCategoria = useMemo(() => {
    const cats: Record<string, number> = {};
    stats.currentGastos.forEach(g => {
      const c = g.category || 'others';
      cats[c] = (cats[c] || 0) + Number(g.total);
    });
    return Object.entries(cats).sort((a, b) => b[1] - a[1]);
  },[stats.currentGastos]);

  const getCategoryStyles = (category: string) => {
    switch (category) {
      case 'dining':
        return { icon: <Utensils size={18} />, color: 'text-orange-400', bg: 'bg-orange-400/10', hex: '#FB923C' };
      case 'health':
        return { icon: <Pill size={18} />, color: 'text-emerald-400', bg: 'bg-emerald-400/10', hex: '#34D399' };
      case 'mini':
        return { icon: <Store size={18} />, color: 'text-brand-accent', bg: 'bg-brand-accent/10', hex: '#00FAD9' };
      case 'super':
        return { icon: <ShoppingCart size={18} />, color: 'text-brand-primary', bg: 'bg-brand-primary/10', hex: '#5D2EEF' };
      case 'others':
        return { icon: <LayoutGrid size={18} />, color: 'text-brand-muted', bg: 'bg-white/5', hex: '#8E94AF' };
      default:
        return { icon: <Tag size={18} />, color: 'text-indigo-400', bg: 'bg-indigo-400/10', hex: '#818CF8' };
    }
  };

  const renderDonutChart = (sizeClass = "w-40 h-40 lg:w-56 lg:h-56") => {
    let cumulativePercent = 0;
    const radius = 70;
    const circumference = 2 * Math.PI * radius;

    return (
      <div className={`relative ${sizeClass} mx-auto flex items-center justify-center`}>
        <svg className="w-full h-full -rotate-90" viewBox="0 0 200 200">
          {statsPorCategoria.map(([cat, val], i) => {
            const percent = (val / (stats.total || 1)) * 100;
            const strokeDasharray = `${(percent * circumference) / 100} ${circumference}`;
            const strokeDashoffset = `-${(cumulativePercent * circumference) / 100}`;
            cumulativePercent += percent;
            const styles = getCategoryStyles(cat);

            return (
              <circle
                key={i}
                cx="100"
                cy="100"
                r={radius}
                fill="transparent"
                stroke={styles.hex}
                strokeWidth="22"
                strokeDasharray={strokeDasharray}
                strokeDashoffset={strokeDashoffset}
                strokeLinecap="round"
                className="transition-all duration-1000 ease-out"
              />
            );
          })}
        </svg>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className="text-[8px] lg:text-[10px] font-black text-brand-muted uppercase tracking-widest">{txt('home.records')}</span>
          <span className="text-xl lg:text-3xl font-black italic text-white tracking-tighter">{stats.currentGastos.length}</span>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-6 lg:space-y-0 lg:grid lg:grid-cols-12 lg:gap-10 lg:items-start animate-in fade-in duration-700 no-scrollbar">

      {/* COLUMNA IZQUIERDA: RESUMEN Y ANÁLISIS */}
      <div className="lg:col-span-5 space-y-6">
        <div className="flex items-center justify-between px-2">
          <button onClick={() => changeMonth(-1)} className="btn-icon !p-1.5 border-none bg-white/5">
            <ChevronLeft size={18} />
          </button>
          <span className="text-[10px] font-black uppercase tracking-[0.3em] text-white/90">
            {currentViewDate.toLocaleDateString(lang, { month: 'long', year: 'numeric' })}
          </span>
          <button 
            onClick={() => changeMonth(1)} 
            disabled={isCurrentMonth}
            className={`btn-icon !p-1.5 border-none bg-white/5 ${isCurrentMonth ? 'opacity-0' : ''}`}
          >
            <ChevronRight size={18} />
          </button>
        </div>

        <button 
          onClick={() => setShowBreakdown(!showBreakdown)}
          className={`w-full text-left relative overflow-hidden card-premium bg-gradient-to-br from-brand-primary to-[#4318BB] border-none shadow-[0_20px_40px_rgba(93,46,239,0.3)] active:scale-[0.98] transition-all duration-500 group ${
            showBreakdown ? '!p-6 lg:!p-8' : '!p-8 lg:!p-10'
          }`}
        >
          <div className="relative z-10">
            <div className="flex justify-between items-start mb-2">
              <p className="text-[10px] font-black uppercase tracking-widest text-white/60">
                  {txt('home.monthly_spend')}
              </p>
              <TrendingUp size={showBreakdown ? 14 : 16} className="text-brand-accent opacity-50 group-hover:scale-125 transition-transform lg:hidden" />
            </div>

            <h2 className={`font-black italic tracking-tighter text-white leading-none transition-all duration-500 ${
              showBreakdown ? 'text-4xl lg:text-6xl' : 'text-6xl lg:text-8xl'
            }`}>
              {stats.total.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}€
            </h2>

            {!showBreakdown && (
              <div className="flex items-center gap-3 mt-10 animate-in fade-in duration-500">
                <div className="px-3 py-1.5 bg-white/10 rounded-full border border-white/5">
                  <span className="text-[9px] font-black uppercase tracking-tighter text-white">
                    {stats.currentGastos.length} {txt('home.records')}
                  </span>
                </div>
                <div className="flex items-center gap-1.5 ml-auto text-[9px] font-black uppercase tracking-widest text-brand-accent lg:hidden">
                  <PieIcon size={12} />
                  {txt('home.analysis')}
                </div>
              </div>
            )}
          </div>
          <div className="absolute -right-4 -bottom-4 w-40 h-40 bg-white/5 rounded-full blur-3xl" />
        </button>

        <div className={`hidden lg:block card-premium bg-white/[0.02] border-white/[0.05] animate-in zoom-in-95`}>
           <h3 className="text-small-caps text-center mb-8">{txt('home.chart_title')}</h3>
           {renderDonutChart()}
           <div className="mt-10 space-y-4">
              {statsPorCategoria.map(([cat, val], i) => {
                const styles = getCategoryStyles(cat);
                return (
                    <div key={i} className="flex justify-between items-center text-[10px] font-black uppercase">
                        <span className="flex items-center gap-2">
                            <div className="w-2.5 h-2.5 rounded-full" style={{backgroundColor: styles.hex}}/> 
                            {cat}
                        </span>
                        <span className="text-white/70">{val.toFixed(2)}€</span>
                    </div>
                );
              })}
           </div>
        </div>
      </div>

      {/* COLUMNA DERECHA: REGISTROS */}
      <div className="lg:col-span-7 space-y-4">
        <div className="flex justify-between items-center px-1">
          <h3 className="text-small-caps">{txt('home.records')}</h3>
        </div>

        <div className="space-y-3">
          {showBreakdown ? (
            <div className="animate-in zoom-in-95 duration-300 py-4 lg:hidden">
               {renderDonutChart("w-48 h-48")}
               <div className="mt-8 space-y-2">
                  {statsPorCategoria.map(([cat, val], i) => (
                    <div key={i} className="row-clickable">
                        <span className="text-[10px] font-black uppercase">{cat}</span>
                        <span className="text-[11px] font-black text-brand-success">{val.toFixed(2)}€</span>
                    </div>
                  ))}
               </div>
            </div>
          ) : (
            stats.currentGastos.length > 0 ? (
              stats.currentGastos.map((g, i) => {
                const styles = getCategoryStyles(g.category);
                return (
                  <button key={i} onClick={() => setSelectedGasto(g)} className="row-clickable">
                    <div className="flex items-center gap-4 text-left overflow-hidden">
                      <div className={`flex-shrink-0 p-3 rounded-2xl ${styles.bg} ${styles.color}`}>{styles.icon}</div>
                      <div className="overflow-hidden">
                        <p className="font-black text-[13px] uppercase text-white truncate leading-tight">{g.comercio}</p>
                        <p className="text-[9px] font-bold text-brand-muted mt-1">{g.fecha}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3 flex-shrink-0">
                      <p className="text-lg font-black text-brand-success tracking-tighter italic">{Number(g.total).toFixed(2)}€</p>
                      <ArrowUpRight size={14} className="text-brand-muted opacity-30" />
                    </div>
                  </button>
                );
              })
            ) : (
              <div className="py-20 text-center border-2 border-dashed border-white/5 rounded-[2.5rem] opacity-30">
                  <p className="text-xs font-bold uppercase tracking-widest">{txt('home.no_records')}</p>
              </div>
            )
          )}
        </div>
      </div>
    </div>
  );
};

export default DashboardView;

"use client";
import React, { useState } from 'react';
import { ChevronLeft, Trash2, Store, ImageIcon, X, Loader2 } from 'lucide-react';
import { getDriveFileBlob } from '@/lib/gdrive';

interface DetailViewProps {
  gasto: any;
  onClose: () => void;
  onDelete: (g: any) => void;
  token: string;
  txt: (key: string) => string;
}

const DetailView: React.FC<DetailViewProps> = ({ gasto, onClose, onDelete, token, txt }) => {
  const [loadingImg, setLoadingImg] = useState(false);
  const [viewerUrl, setViewerUrl] = useState<string | null>(null);

  const openTicket = async (id: string) => {
    setLoadingImg(true);
    try {
      const url = await getDriveFileBlob(token, id);
      if (url) setViewerUrl(url);
    } catch (e) {
      console.error("Error loading image", e);
    } finally {
      setLoadingImg(false);
    }
  };

  return (
    <div className="modal-content-full !p-5 flex flex-col animate-in slide-in-from-right-4">
      {/* HEADER COMPACTO */}
      <div className="flex justify-between items-center mb-4">
        <button onClick={onClose} className="btn-icon !p-2 bg-brand-secondary/20 border-none">
          <ChevronLeft size={20} />
        </button>
        <div className="text-center overflow-hidden">
            <h2 className="text-[14px] font-black italic text-brand-primary uppercase truncate max-w-[180px]">
                {gasto.comercio}
            </h2>
            <p className="text-[8px] font-bold text-brand-muted uppercase tracking-[0.2em]">
                {gasto.fecha}
            </p>
        </div>
        <button onClick={() => onDelete(gasto)} className="btn-icon !p-2 text-brand-danger/40 bg-brand-danger/5 border-none">
          <Trash2 size={20} />
        </button>
      </div>

      {/* LISTADO DE PRODUCTOS */}
      <div className="flex-1 overflow-y-auto no-scrollbar mb-4 border-y border-white/[0.03]">
        {gasto.productos?.map((p: any, i: number) => (
          <div key={i} className="flex justify-between items-center py-3 border-b border-white/[0.02] last:border-none">
            <div className="flex-1 pr-4 overflow-hidden">
              <p className="text-[11px] font-black uppercase text-white leading-tight">
                {p.nombre_base}
              </p>
              <p className="text-[8px] font-bold text-brand-muted uppercase truncate opacity-20 mt-0.5">
                {p.nombre_ticket}
              </p>
            </div>
            <div className="text-right">
                <span className="block font-black italic text-brand-success tracking-tighter text-[11px]">
                    {Number(p.subtotal).toFixed(2)}€
                </span>
                <span className="text-[7px] font-bold text-brand-muted opacity-40 uppercase">x{p.cantidad || 1}</span>
            </div>
          </div>
        ))}
      </div>

      {/* FOOTER: TOTAL Y TICKETS */}
      <div className="flex items-stretch gap-2 h-20">
        <div className="flex-[1.2] bg-white/[0.03] p-3 rounded-2xl border border-white/[0.05] flex flex-col justify-center">
            <p className="text-[7px] font-black uppercase text-brand-muted mb-0.5 opacity-30">
              {txt('detail.investment')}
            </p>
            <div className="flex items-baseline gap-0.5">
                <span className="text-2xl font-black italic text-white tracking-tighter">
                    {Number(gasto.total).toFixed(2)}
                </span>
                <span className="text-xs font-black italic text-brand-success">€</span>
            </div>
        </div>

        <div className="flex-[2] overflow-x-auto no-scrollbar flex items-center gap-2">
            {gasto.photoIds && gasto.photoIds.length > 0 ? (
                gasto.photoIds.map((id: string, idx: number) => (
                    <button 
                        key={id} 
                        onClick={() => openTicket(id)}
                        className="h-full flex-none bg-brand-card border border-white/[0.1] px-4 rounded-2xl flex flex-col items-center justify-center gap-1 active:scale-95 transition-all"
                    >
                        <ImageIcon size={16} className="text-brand-primary" />
                        <span className="text-[7px] font-black uppercase tracking-widest text-brand-muted">
                          {txt('detail.ticket_label')} {idx + 1}
                        </span>
                    </button>
                ))
            ) : (
                <div className="h-full flex-1 flex items-center justify-center border border-dashed border-white/5 rounded-2xl">
                    <p className="text-[8px] font-bold text-brand-muted uppercase italic">
                      {txt('detail.no_photos')}
                    </p>
                </div>
            )}
        </div>
      </div>

      {/* LIGHTBOX VISOR */}
      {viewerUrl && (
        <div className="modal-overlay !p-4 z-[2000] animate-in fade-in backdrop-blur-xl" onClick={() => setViewerUrl(null)}>
          <button className="absolute top-6 right-6 btn-icon !bg-white/10 border-white/20 z-[600] !p-3">
            <X size={24} className="text-white" />
          </button>
          <img src={viewerUrl} className="max-w-full max-h-[90vh] rounded-3xl shadow-2xl object-contain border border-white/10 animate-in zoom-in-95" alt="Receipt" />
        </div>
      )}

      {loadingImg && (
        <div className="fixed inset-0 z-[2100] bg-brand-bg/80 backdrop-blur-md flex items-center justify-center">
            <Loader2 className="animate-spin text-brand-primary" size={40} strokeWidth={3} />
        </div>
      )}
    </div>
  );
};

export default DetailView;

"use client";
import React, { useState } from 'react';
import { 
  X, 
  ChevronRight, 
  ChevronLeft, 
  LayoutGrid, 
  Plus, 
  History, 
  Settings, 
  BarChart3, 
  Camera, 
  CheckCircle2,
  Sparkles
} from 'lucide-react';

interface HelpModalProps {
  onClose: () => void;
  txt: (key: string) => string;
}

const HelpModal: React.FC<HelpModalProps> = ({ onClose, txt }) => {
  const [currentStep, setCurrentStep] = useState(0);

  const steps = [
    {
      title: txt('help.home_title'),
      desc: txt('help.home_desc'),
      icon: <BarChart3 size={40} className="text-brand-primary" />,
      color: "bg-brand-primary/10"
    },
    {
      title: txt('help.nav_title'),
      desc: txt('help.nav_desc'),
      icon: (
        <div className="flex gap-2">
            <LayoutGrid size={24} className="text-brand-muted" />
            <div className="w-10 h-10 bg-brand-primary rounded-xl flex items-center justify-center -top-2 relative shadow-lg">
                <Plus size={24} className="text-white" />
            </div>
            <History size={24} className="text-brand-muted" />
        </div>
      ),
      color: "bg-brand-secondary/30"
    },
    {
      title: txt('help.scanner_title'),
      desc: txt('help.scanner_desc'),
      icon: <Camera size={40} className="text-brand-accent" />,
      color: "bg-brand-accent/10"
    },
    {
      title: txt('help.list_title'),
      desc: txt('help.list_desc'),
      icon: <CheckCircle2 size={40} className="text-brand-success" />,
      color: "bg-brand-success/10"
    },
    {
      title: txt('help.settings_title'),
      desc: txt('help.settings_desc'),
      icon: <Settings size={40} className="text-brand-muted" />,
      color: "bg-white/5"
    }
  ];

  const next = () => {
    if (currentStep < steps.length - 1) setCurrentStep(currentStep + 1);
    else onClose();
  };

  const prev = () => {
    if (currentStep > 0) setCurrentStep(currentStep - 1);
  };

  return (
    <div className="modal-overlay !p-6 z-[3000]">
      <div className="card-premium max-w-sm w-full relative overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col min-h-[450px]">

        {/* HEADER */}
        <div className="flex justify-between items-center mb-8">
          <div className="flex items-center gap-2">
            <Sparkles size={16} className="text-brand-accent" />
            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-brand-muted">
                {txt('help.onboarding_title')}
            </span>
          </div>
          <button onClick={onClose} className="btn-icon !p-1.5 border-none bg-white/5">
            <X size={18} />
          </button>
        </div>

        {/* CONTENIDO DINÁMICO */}
        <div className="flex-1 flex flex-col items-center text-center justify-center space-y-6 px-2">
          <div className={`w-24 h-24 rounded-[2rem] ${steps[currentStep].color} flex items-center justify-center mb-2 animate-in fade-in zoom-in duration-500`}>
            {steps[currentStep].icon}
          </div>

          <div className="space-y-3">
            <h3 className="text-2xl font-black italic uppercase tracking-tighter text-white">
                {steps[currentStep].title}
            </h3>
            <p className="text-xs font-bold text-brand-muted leading-relaxed uppercase opacity-80">
                {steps[currentStep].desc}
            </p>
          </div>
        </div>

        {/* INDICADORES DE PASO (DOTS) */}
        <div className="flex justify-center gap-2 mb-8">
          {steps.map((_, i) => (
            <div 
              key={i} 
              className={`h-1.5 rounded-full transition-all duration-300 ${
                i === currentStep ? 'w-8 bg-brand-primary' : 'w-2 bg-white/10'
              }`} 
            />
          ))}
        </div>

        {/* BOTONES DE NAVEGACIÓN */}
        <div className="flex gap-3">
          {currentStep > 0 && (
            <button 
              onClick={prev} 
              className="btn-secondary !py-4 flex-1"
            >
              <ChevronLeft size={18} />
            </button>
          )}

          <button 
            onClick={next} 
            className="btn-primary !py-4 flex-[2] shadow-xl"
          >
            <span>{currentStep === steps.length - 1 ? txt('help.finish') : txt('help.next')}</span>
            {currentStep < steps.length - 1 && <ChevronRight size={18} />}
          </button>
        </div>

        {/* DECORACIÓN DE FONDO */}
        <div className="absolute -bottom-10 -right-10 w-32 h-32 bg-brand-primary/5 rounded-full blur-3xl pointer-events-none" />
      </div>
    </div>
  );
};

export default HelpModal;

"use client";
