/**
 * v2.0: Se elimina la dependencia de OCR local.
 * Envía las imágenes capturadas directamente al pipeline distribuido del servidor.
 */
export const analyzeReceipt = async (images: string[], mode: string, customPrompt: string) => {
  try {
    if (mode === 'manual') {
      return { 
        comercio: "INGRESO MANUAL", 
        fecha: new Date().toLocaleDateString("es-ES"), 
        total: 0, 
        productos: []
      };
    }

    console.log("[V2.0] Enviando imágenes al Pipeline de Servidor...", images);

    if (!images || !Array.isArray(images) || images.length === 0) {
      throw new Error(`No hay imágenes válidas. Recibido: ${JSON.stringify(images)}`);
    }

    const response = await fetch("/api/analyze", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
            images: images, // Array de base64
            prompt: customPrompt,
            mode: mode
        })
    });

    if (!response.ok) {
        const errData = await response.json().catch(() => ({ error: "Error de red" }));
        throw new Error(errData.error || `Error en el servidor: ${response.status}`);
    }

    const result = await response.json();

    // Normalización de seguridad
    return {
      comercio: (result.comercio || "DESCONOCIDO").toUpperCase().trim(),
      fecha: result.fecha || new Date().toLocaleDateString("es-ES"),
      total: Number(result.total) || 0,
      productos: (result.productos || []).map((p: any) => ({
        cantidad: Number(p.cantidad) || 1,
        nombre_ticket: String(p.nombre_ticket || "PRODUCTO"),
        nombre_base: String(p.nombre_base || p.nombre_ticket || "PRODUCTO"),
        subtotal: Number(p.subtotal) || 0
      }))
    };

  } catch (error: any) {
    console.error("Error en analyzeReceipt v2.0:", error);
    throw new Error(error.message || "No se pudo procesar el ticket con la nueva IA.");
  }
};

/* --- ARCHIVO: lib/i18n.ts --- */
import es from '../locales/es.json';
import en from '../locales/en.json';

/**
 * Diccionario de traducciones que importa los archivos JSON externos.
 * Esto permite que el código sea agnóstico al contenido de los textos.
 */
const translations: any = { es, en };

/**
 * Detecta el idioma preferido del sistema o navegador.
 * @returns 'es' o 'en' dependiendo de la configuración del usuario.
 */
export const getSystemLanguage = (): string => {
  if (typeof window === 'undefined') return 'es';

  // navigator.language suele devolver algo como "es-ES" o "en-US"
  // Dividimos por el guion para quedarnos solo con el código de idioma ("es" o "en")
  const lang = navigator.language.split('-')[0];

  // Si el idioma detectado existe en nuestro diccionario, lo devolvemos;
  // de lo contrario, devolvemos 'es' por defecto.
  return translations[lang] ? lang : 'es';
};

/**
 * Función principal de traducción (Translate).
 * @param path Cadena con puntos que indica la ruta en el JSON (ej: 'auth.title')
 * @param lang El idioma actual seleccionado en la aplicación ('es' o 'en')
 * @returns El texto traducido o la ruta en mayúsculas si no se encuentra.
 */
export const t = (path: string, lang: string): string => {
  if (!path) return "";

  const keys = path.split('.');

  // Seleccionamos el objeto de traducción correspondiente al idioma, 
  // cayendo siempre en español como idioma de respaldo (fallback).
  let result = translations[lang] || translations['es'];

  // Navegamos recursivamente por el objeto usando las llaves del path
  for (const key of keys) {
    if (result && result[key] !== undefined) {
      result = result[key];
    } else {
      // Si en algún punto la llave no existe, registramos el error en consola
      // y devolvemos la ruta solicitada para identificar el error visualmente.
      console.warn(`[i18n] Error: No se encontró la llave "${path}" para el idioma "${lang}"`);
      return path.toUpperCase(); 
    }
  }

  return result;
};

/* --- ARCHIVO: lib/products.ts --- */
import { supabase } from "./supabase";

/**
 * Normaliza un texto para comparaciones (quita acentos y Ñ)
 */
const toFuzzy = (txt: string) => {
  return txt.toUpperCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/Ñ/g, "N")
    .trim();
};

/**
 * BUSCADOR PARA "MI LISTA"
 * Busca ignorando acentos/Ñ y ordena por longitud (más corto primero).
 */
export const searchLocalProducts = async (query: string) => {
  if (query.length < 2) return [];
  const upperQuery = query.toUpperCase().trim();
  const fuzzyQuery = toFuzzy(upperQuery);

  try {
    const { data, error } = await supabase.from('productos')
      .select(`id, nombre_base`)
      .or(`nombre_base.ilike.%${upperQuery}%, nombre_base.ilike.%${fuzzyQuery}%`)
      .limit(30);

    if (error) throw error;

    // Ordenamos por longitud: "PIÑA" antes que "PIÑA NATURAL"
    return (data || []).sort((a, b) => a.nombre_base.length - b.nombre_base.length);
  } catch (e) {
    console.error("Error en búsqueda:", e);
    return [];
  }
};

/**
 * OBTIENE EL ÚLTIMO PRECIO REGISTRADO
 * Se usa en la fase de revisión para comparar si el producto subió o bajó.
 */
export const getLastPrice = async (nombreBase: string): Promise<number | null> => {
  try {
    const fuzzyBase = toFuzzy(nombreBase);

    // 1. Buscamos el ID del producto por su nombre base
    const { data: prod } = await supabase
      .from('productos')
      .select('id, nombre_base')
      .filter('nombre_base', 'ilike', nombreBase)
      .maybeSingle();

    if (!prod) return null;

    // 2. Buscamos en detalles el último precio registrado
    const { data: detalle, error } = await supabase
      .from('producto_detalles')
      .select('ultimo_precio')
      .eq('producto_id', prod.id)
      .order('fecha_actualizacion', { ascending: false })
      .limit(1)
      .maybeSingle();

    if (error || !detalle) return null;
    return detalle.ultimo_precio;
  } catch (e) {
    console.error("Error al obtener precio histórico:", e);
    return null;
  }
};

/**
 * BUSCADOR DE ALIAS (Diccionario Inteligente)
 */
export const getBaseNameFromAlias = async (nombreTicket: string): Promise<string | null> => {
  try {
    const ticketUpper = nombreTicket.toUpperCase().trim();
    const { data, error } = await supabase
      .from('producto_alias')
      .select('productos(nombre_base)')
      .eq('nombre_ticket', ticketUpper)
      .maybeSingle();

    if (error) return null;
    // @ts-ignore
    return data?.productos?.nombre_base || null;
  } catch (e) {
    return null;
  }
};

/**
 * REGISTRO DE APRENDIZAJE Y FUSIÓN TOTAL
 */
export const saveManualAlias = async (nombreTicket: string, nombreBase: string) => {
  try {
    const ticketUpper = nombreTicket.toUpperCase().trim();
    const baseUpper = nombreBase.toUpperCase().trim();

    if (!ticketUpper || !baseUpper) return;

    // Blindaje contra nombres sucios
    if (ticketUpper === baseUpper) return;

    const fuzzyBase = toFuzzy(baseUpper);

    // 1. Buscamos si ya existe (Fuzzy)
    let { data: existentes } = await supabase.from('productos').select('id, nombre_base');
    let prod = existentes?.find(p => toFuzzy(p.nombre_base) === fuzzyBase);

    // 2. Si es nuevo, crear
    if (!prod) {
      const { data: newP, error: errorInsert } = await supabase
        .from('productos')
        .insert([{ nombre_base: baseUpper, categoria: 'OTROS' }])
        .select()
        .single();

      if (!errorInsert) prod = newP;
    }

    // 3. Vincular alias
    if (prod) {
      await supabase.from('producto_alias').upsert({ 
        producto_id: prod.id, 
        nombre_ticket: ticketUpper 
      }, { onConflict: 'nombre_ticket' });
    }
  } catch (e) {
    console.error("Error en saveManualAlias:", e);
  }
};

/**
 * SINCRONIZACIÓN POST-COMPRA
 * Actualiza el catálogo global y los precios de referencia.
 */
export const syncProductWithSupabase = async (itemIA: any, comercio: string) => {
  try {
    const baseUpper = itemIA.nombre_base.toUpperCase().trim();
    const ticketUpper = itemIA.nombre_ticket.toUpperCase().trim();

    // Guardamos el alias primero (IA Aprendizaje)
    await saveManualAlias(ticketUpper, baseUpper);

    const fuzzyBase = toFuzzy(baseUpper);
    const { data: existentes } = await supabase.from('productos').select('id, nombre_base');
    const prod = existentes?.find(p => toFuzzy(p.nombre_base) === fuzzyBase);

    if (prod) {
      const subtotal = Number(itemIA.subtotal) || 0;
      const cantidad = Number(itemIA.cantidad) || 1;
      const precioUnitario = subtotal / cantidad;

      // Upsert en detalles: Si ya existe para ese tamaño/id, actualiza el precio y fecha
      await supabase.from('producto_detalles').upsert({
        producto_id: prod.id,
        marca: 'GENERICO',
        tamano: 'UNICO',
        ultimo_precio: precioUnitario,
        ultimo_comercio: comercio.toUpperCase().trim(),
        fecha_actualizacion: new Date().toISOString()
      }, { onConflict: 'producto_id, tamano' });
    }
  } catch (e) {
    console.error("Error en sincronización:", e);
  }
};

import { createClient } from '@supabase/supabase-js';
import { SUPABASE_URL, SUPABASE_ANON_KEY } from './config';

// Si las variables no existen, ponemos strings vacíos para que no rompa el build
// Pero en Vercel funcionará porque las tomará de las "Environment Variables"
const supabaseUrl = SUPABASE_URL || 'https://placeholder.supabase.co';
const supabaseAnonKey = SUPABASE_ANON_KEY || 'placeholder';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

export interface Product {
  cantidad: number;
  nombre_ticket: string;
  nombre_base: string;
  subtotal: number;
}

export interface Gasto {
  comercio: string;
  fecha: string; // DD/MM/YYYY
  total: number;
  category: string;
  photoIds: string[];
  productos: Product[];
  usedList?: boolean;
}

export interface ListItem {
  name: string;
  checked: boolean;
  confirmed: boolean;
}

export interface AppDB {
  gastos: Gasto[];
  lista: ListItem[];
  customCategories: string[];
}

export interface UserState {
  name: string;
  loggedIn: boolean;
  token: string;
}

/**
 * Normaliza texto: minúsculas, quita acentos y carácteres especiales.
 */
export const normalizeText = (text: string): string => {
  if (!text) return "";
  return text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^a-z0-9 ]/g, " ")
    .trim();
};

/**
 * Normaliza nombres de comercios para fusionarlos.
 */
export const normalizeStoreName = (name: string): string => {
  if (!name) return "DESCONOCIDO";
  return name
    .toUpperCase()
    .replace(/\s+(S\.A\.|S\.L\.|S\.L\.U\.|SA|SL|INC|CORP)$/g, "")
    .replace(/[.,]/g, "")
    .trim();
};

/**
 * Calcula la afinidad entre un nombre de ticket y un ítem de la lista.
 */
export const calculateMatchScore = (ticketName: string, listName: string): number => {
  const tWords = normalizeText(ticketName).split(/\s+/);
  const lWords = normalizeText(listName).split(/\s+/);

  let score = 0;
  lWords.forEach(word => {
    if (word.length <= 2) return; 
    if (tWords.includes(word)) score += 10; 
    else if (tWords.some(tw => tw.includes(word) || word.includes(tw))) score += 5; 
  });

  return score;
};

/**
 * AGRUPACIÓN DE PRODUCTOS REPETIDOS
 */
export const groupRepeatedProducts = (products: any[]) => {
  const map = new Map();
  products.forEach(p => {
    const key = p.nombre_ticket.toUpperCase().trim();
    if (map.has(key)) {
      const existing = map.get(key);
      existing.cantidad = (existing.cantidad || 1) + (p.cantidad || 1);
      existing.subtotal = Number(existing.subtotal) + Number(p.subtotal);
    } else {
      map.set(key, { ...p, cantidad: p.cantidad || 1 });
    }
  });
  return Array.from(map.values());
};

/**
 * COMPRESIÓN DE ALTA FIDELIDAD PARA GEMINI
 * Optimizada para aprovechar la capacidad multilineal de Gemini Flash 1.5/2.0.
 * Mantenemos un margen para el límite de 4.5MB de Vercel API.
 * 
 * La compresión de imágenes se ha eliminado para maximizar la calidad del OCR.
 * Ahora, `compressImage` simplemente devuelve la imagen original en base64.
 */
export const compressImage = (base64Str: string): Promise<string> => {
  return Promise.resolve(base64Str);
};

/**
 * Exporta los gastos a formato CSV descargable.
 */
export const exportToCSV = (gastos: any[]) => {
  if (!gastos || gastos.length === 0) return;
  const headers = ["Fecha", "Comercio", "Total", "Productos"];
  const rows = gastos.map(g => [g.fecha, `"${g.comercio}"`, g.total, `"${g.productos?.map((p: any) => p.nombre_base).join(" | ")}"`]);
  const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
  const blob = new Blob([`\ufeff${csvContent}`], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement("a");
  link.setAttribute("href", url);
  link.setAttribute("download", `mis_gastos_${new Date().toISOString().split('T')[0]}.csv`);
  link.click();
};

/**
 * PREPROCESADO AVANZADO PARA OCR (CLIENT-SIDE)
 * Aplica escalado, escala de grises, contraste dinámico y threshold.
 */
export const preprocessForOCR = (base64Str: string, mode: 'high' | 'moderate' = 'high'): Promise<string> => {
  return new Promise((resolve) => {
    const img = new Image();
    img.src = base64Str;
    img.crossOrigin = "anonymous";
    img.onload = () => {
      const canvas = document.createElement('canvas');
      // Escalado 2x para mejorar precisión de OCR
      const scale = 2;
      const width = img.width * scale;
      const height = img.height * scale;

      canvas.width = width;
      canvas.height = height;

      const ctx = canvas.getContext('2d', { willReadFrequently: true });
      if (!ctx) return resolve(base64Str);

      ctx.imageSmoothingEnabled = true;
      ctx.imageSmoothingQuality = 'high';
      ctx.drawImage(img, 0, 0, width, height);

      const imageData = ctx.getImageData(0, 0, width, height);
      const data = imageData.data;

      // Threshold dinámico basado en el modo
      const threshold = mode === 'high' ? 120 : 150;

      for (let i = 0; i < data.length; i += 4) {
        const r = data[i];
        const g = data[i + 1];
        const b = data[i + 2];

        // Escala de grises (Luminosidad)
        const gray = 0.299 * r + 0.587 * g + 0.114 * b;

        // Contraste y Threshold (Binarización Blanco/Negro)
        // Si es más oscuro que el threshold, negro puro; si no, blanco puro.
        const v = gray < threshold ? 0 : 255;

        data[i] = data[i+1] = data[i+2] = v;
      }

      ctx.putImageData(imageData, 0, 0);
      resolve(canvas.toDataURL('image/jpeg', 0.9));
    };
    img.onerror = () => resolve(base64Str);
  });
};

/**
 * LIMPIEZA INTELIGENTE DE TEXTO OCR
 */
export const cleanOCRText = (text: string): string => {
  const lines = text.split("\n");
  const cleanedLines: string[] = [];

  for (const line of lines) {
    let cleanLine = line.trim();

    // 1. Correcciones comunes de caracteres
    cleanLine = cleanLine
      .replace(/([0-9])O/g, "$10") // Número seguido de O -> 0
      .replace(/O([0-9])/g, "0$1") // O seguido de número -> 0
      .replace(/([0-9])l/g, "$11") // Número seguido de l -> 1
      .replace(/l([0-9])/g, "1$1") // l seguido de número -> 1
      .replace(/\|/g, "1")        // | -> 1
      .replace(/[^\w\s.,€$*%+-/]/g, ""); // Eliminar caracteres basura

    // 2. Normalización de precios (0,80 -> 0.80)
    cleanLine = cleanLine.replace(/(\d+),(\d{2})\b/g, "$1.$2");

    // 3. Filtrado de líneas vacías o irrelevantes
    // Una línea se considera relevante si tiene más de 3 caracteres O contiene al menos un número y es más larga que 1 caracter
    const containsNumber = /\d/.test(cleanLine);
    const isMeaningful = cleanLine.length > 3 || (containsNumber && cleanLine.length > 1);

    if (isMeaningful) {
      cleanedLines.push(cleanLine);
    }
  }

  return Array.from(new Set(cleanedLines)).join("\n"); // Eliminar duplicados y unir
};

